// CORRECT: seat hold before payment
async handle(input: SeatReservationInput): Promise<DataProcessResult<SeatResult>> {
  // ORDER 1: atomic seat hold with TTL
  const hold = await this.seatReservationService.reserveSeat(input.eventId, input.attendeeId, TTL_MS);
  if (!hold.isSuccess) return DataProcessResult.failure('SEAT_UNAVAILABLE', 'No seats available');
  // ORDER 2: initiate payment AFTER confirmed seat hold
  await this.queue.enqueue('PaymentRequested', { purchaseId, seatHoldId: hold.data.holdId, amount });
  return DataProcessResult.success({ holdId: hold.data.holdId });
  // WRONG: enqueue('PaymentRequested') BEFORE reserveSeat — double-booking race on last ticket
}

// CORRECT: fail-open with audit
try {
  const result = await this.fraudService.check(purchaseId, userId, tenantId);
  return result;
} catch (e) {
  // BOTH conditions required:
  await this.queue.enqueue('FraudCheckFailed', { reason: 'service_unavailable', purchaseId, tenantId });
  return { passed: true }; // fail OPEN — purchase proceeds during outage
  // WRONG: return { passed: false } — blocks all purchases when fraud service is down
}

// CORRECT: all-or-nothing group booking
async handle(input: GroupBookingInput): Promise<DataProcessResult<GroupBookingResult>> {
  const tickets = await this.db.transaction(async (tx) => {
    return Promise.all(input.groupMembers.map(member =>
      tx.storeDocument('xiigen-tickets', { memberId: member.id, eventId: input.eventId, tenantId })
    ));
  });
  return DataProcessResult.success({ ticketCount: tickets.length });
  // WRONG: for (const member of input.groupMembers) { await this.db.storeDocument(...) }
  // ^ loop outside transaction — partial success on member 4 of 6 failure
}

// CORRECT: inline-pure computation
@Injectable()
export class FeeCalculatorHandler {
  calculate(baseAmount: number, tier: string, config: FeeConfig): FeeBreakdown {
    const platformFee = baseAmount * config.platformRate;
    const baseFee = baseAmount - platformFee;
    return { baseFee, platformFee, totalFee: baseAmount };
  }
  // NO storeDocument, NO enqueue, NO @EventPattern
}
